/* ---------- what keating does / capabilities ---------- */
.retro-layout .caps {
  padding: 84px 0 90px;
  border-top: 1.5px dashed var(--line);
}

.retro-layout .caps-head {
  margin-bottom: 38px;
}

.retro-layout .caps-head .section-title {
  margin-top: 14px;
}

.retro-layout .caps-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 18px;
}

.retro-layout .cap-card {
  background: var(--card);
  border: 1.5px solid var(--ink);
  padding: 24px 22px 26px;
  box-shadow: var(--shadow-card);
  transition: transform 0.16s ease, box-shadow 0.16s ease;
}

.retro-layout .cap-card:hover {
  transform: translateY(-4px);
  box-shadow: 5px 5px 0 var(--ink);
}

.retro-layout .cap-icon {
  width: 62px;
  height: auto;
  margin-bottom: 16px;
  color: var(--accent-dim);
  transition: transform 0.25s cubic-bezier(0.34, 1.56, 0.64, 1);
}

.dark .retro-layout .cap-icon {
  color: var(--phosphor);
}

.retro-layout .cap-card:hover .cap-icon {
  transform: rotate(-5deg) scale(1.08);
}

.retro-layout .cap-card h3 {
  font-family: var(--mono-display);
  font-size: 15.5px;
  letter-spacing: 0.02em;
  margin-bottom: 8px;
  line-height: 1.4;
  color: var(--ink);
}

.retro-layout .cap-card p {
  color: var(--ink-soft);
  font-size: 12.8px;
  line-height: 1.7;
}

/* ---------- CRT verse ---------- */
.retro-layout .verse {
  padding: 30px 0 96px;
  text-align: center;
  background:
    radial-gradient(ellipse 60% 55% at 50% 62%, rgba(75, 227, 136, 0.12), transparent 70%);
}

.retro-layout .verse-prompt {
  font-size: 11px;
  letter-spacing: 0.2em;
  color: var(--ink-soft);
  margin-bottom: 30px;
}

.retro-layout .crt-wrap {
  position: relative;
  max-width: 620px;
  margin: 0 auto;
  transition: transform 0.3s ease;
}

.retro-layout .crt-wrap:hover {
  transform: scale(1.015);
}

.retro-layout .crt-frame {
  background: #1c1c1c;
  border-radius: 16px;
  padding: 14px 14px 24px;
  box-shadow:
    0 0 0 2px #3a3a3a,
    0 0 0 4px #1c1c1c,
    0 26px 32px rgba(28, 33, 27, 0.3),
    inset 0 0 20px rgba(0, 0, 0, 0.5);
  position: relative;
}

.retro-layout .crt-frame::before {
  content: '';
  position: absolute;
  bottom: 4px;
  left: 50%;
  transform: translateX(-50%);
  width: 60px;
  height: 6px;
  background: #3a3a3a;
  border-radius: 3px;
}

.retro-layout .crt-screen {
  position: relative;
  background: var(--terminal);
  border-radius: 6px;
  padding: 46px 28px;
  overflow: hidden;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  min-height: 180px;
}

.retro-layout .crt-screen::after {
  content: '';
  position: absolute;
  inset: 0;
  pointer-events: none;
  background: repeating-linear-gradient(0deg, rgba(0, 0, 0, 0.35) 0 1px, transparent 1px 3px);
}

.retro-layout .crt-text {
  font-family: var(--mono-display);
  font-weight: 700;
  font-style: italic;
  font-size: clamp(13px, 2.5vw, 19px);
  line-height: 1.55;
  color: var(--phosphor);
  text-shadow: 0 0 14px rgba(75, 227, 136, 0.6), 0 0 36px rgba(75, 227, 136, 0.3);
  animation: retro-flicker 6s linear infinite;
  position: relative;
  z-index: 1;
}

.retro-layout .crt-attr {
  position: relative;
  z-index: 1;
  margin-top: 10px;
  font-size: clamp(8px, 1.4vw, 11px);
  letter-spacing: 0.18em;
  color: var(--phosphor-dim);
  animation: retro-flicker 6s linear infinite;
}

@keyframes retro-flicker {
  0%, 100% { opacity: 1; }
  3% { opacity: 0.92; }
  6% { opacity: 1; }
  42% { opacity: 1; }
  43% { opacity: 0.88; }
  44% { opacity: 1; }
  71% { opacity: 0.95; }
  72% { opacity: 1; }
}

