  const realShare = clamp(0.5 + Math.min(0.4, realOutcomeCount / 20), 0.5, 0.9);
  const syntheticShare = 1 - realShare;
  return clamp(realScore * realShare + syntheticMean * syntheticShare, 0, 1);
}

