export const DEFAULT_WEIGHTS: SimulationWeights = {
  masteryGain: 0.34,
  retention: 0.20,
  engagement: 0.16,
  transfer: 0.16,
  confusion: 0.14
};

export function clampWeights(weights: SimulationWeights): SimulationWeights {
