    retention: clamp(normalized.retention, 0.01, 1),
    engagement: clamp(normalized.engagement, 0.01, 1),
    transfer: clamp(normalized.transfer, 0.01, 1),
    confusion: clamp(normalized.confusion, 0.01, 1)
