    masteryGain: clamped.masteryGain / clampedSum,
    retention: clamped.retention / clampedSum,
    engagement: clamped.engagement / clampedSum,
    transfer: clamped.transfer / clampedSum,
    confusion: clamped.confusion / clampedSum
