export async function listArtifacts(cwd: string): Promise<Array<{ label: string; path: string }>> {
  await ensureProjectScaffold(cwd);
  const roots = [
    plansDir(cwd),
    mapsDir(cwd),
    animationsDir(cwd),
    benchmarksDir(cwd),
    evolutionDir(cwd),
    promptEvolutionDir(cwd),
    tracesDir(cwd),
