		.map((line, index) => `<text x="${x}" y="${y + index * size * 1.25}" text-anchor="${anchor}" font-family="Inter, ui-sans-serif, system-ui, sans-serif" font-size="${size}" font-weight="${weight}" fill="${fill}">${escapeHtml(line)}</text>`)
		.join("\n");
}

