        learners.push({
            id: `learner-${seed}-${index}`,
            priorKnowledge: prng.next(),
            abstractionComfort: prng.next(),
            analogyNeed: prng.next(),
            dialoguePreference: prng.next(),
            diagramAffinity: prng.next(),
            persistence: prng.next(),
            transferDesire: prng.next(),
            anxiety: prng.next(),
        });
