			const cursor = req.result;
			if (cursor) {
				results.push(cursor.value);
				cursor.continue();
			} else {
				// sort newest first
				results.sort((a, b) => b.createdAt.localeCompare(a.createdAt));
				resolve(results);
			}
		};
		req.onerror = () => reject(req.error);
	});
}

