function browserMessageText(message) {
    const content = message.content;
    if (typeof content === "string")
        return content.trim();
    if (Array.isArray(content)) {
        return content
            .map((item) => {
            if (typeof item === "string")
                return item;
            if (item && typeof item === "object" && typeof item.text === "string") {
                return item.text;
            }
            return "";
        })
            .filter(Boolean)
            .join(" ")
            .trim();
    }
    return "";
}
