 /* ---------- hero terminal ---------- */
 .retro-layout .term {
   position: relative;
   z-index: 1;
   background: var(--terminal);
   border: 1.5px solid var(--ink);
   box-shadow: 6px 6px 0 var(--ink);
 }

 .retro-layout .term-bar {
   display: flex;
   align-items: center;
   gap: 8px;
   padding: 11px 14px;
   background: var(--terminal-edge);
   border-bottom: 1px solid rgba(75, 227, 136, 0.18);
 }

 .retro-layout .term-bar .d {
   width: 11px;
   height: 11px;
   border-radius: 50%;
 }

 .retro-layout .term-bar .d.r {
   background: var(--red);
 }

 .retro-layout .term-bar .d.y {
   background: var(--amber);
 }

 .retro-layout .term-bar .d.g {
   background: var(--accent);
 }

 .retro-layout .term-title {
   margin-left: 8px;
   font-size: 11px;
   letter-spacing: 0.14em;
   color: var(--phosphor-dim);
 }

 .retro-layout .term-body {
   position: relative;
   padding: 22px 24px 26px;
   min-height: 380px;
   font-size: 13.5px;
   line-height: 1.85;
   color: var(--phosphor);
 }

 .retro-layout .term-body::after {
   content: '';
   position: absolute;
   inset: 0;
   pointer-events: none;
   background: repeating-linear-gradient(0deg, rgba(0, 0, 0, 0.16) 0 1px, transparent 1px 3px);
   mix-blend-mode: multiply;
 }

 .retro-layout .t-line {
   white-space: pre-wrap;
   word-break: break-word;
   min-height: 1.85em;
 }

 .retro-layout .t-cmd {
   color: #dcefe0;
 }

 .retro-layout .t-cmd::before {
   content: 'keating@harness:~$ ';
   color: var(--phosphor-dim);
 }

 .retro-layout .t-sys {
   color: var(--phosphor-dim);
   font-style: italic;
 }

 .retro-layout .t-you {
   color: var(--amber);
 }

 .retro-layout .t-you::before {
   content: 'you      │ ';
   color: rgba(232, 163, 61, 0.55);
 }

 .retro-layout .t-k {
   color: var(--phosphor);
 }

 .retro-layout .t-k::before {
   content: 'keating  │ ';
   color: var(--phosphor-dim);
 }

 .retro-layout .t-ok {
   color: var(--phosphor);
   font-weight: 600;
 }

 .retro-layout .t-ok::before {
   content: '✓ ';
   color: var(--accent);
 }

 .retro-layout .t-caret {
   display: inline-block;
   width: 8px;
   height: 15px;
   background: var(--phosphor);
   vertical-align: -2px;
   animation: retro-cursor-blink 1s steps(1) infinite;
 }

 .retro-layout .term-foot {
   display: flex;
   gap: 0;
   border-top: 1.5px solid var(--ink);
   background: var(--card);
   font-size: 11px;
   letter-spacing: 0.1em;
 }

 .retro-layout .term-foot div {
   padding: 9px 14px;
   border-right: 1px solid var(--line);
   display: flex;
   align-items: center;
   gap: 8px;
