const fs = require('node:fs');
const path = require('node:path');

const htmlPath = '/home/diogenes/Downloads/keating-landing(1).html';
const outDir = '/home/diogenes/Projects/keating/web/public/brand';
const html = fs.readFileSync(htmlPath, 'utf-8');

// Find all data:image/png;base64 occurrences in order
const regex = /data:image\/png;base64,([A-Za-z0-9+/=]+)/g;
const matches = [];
let m;
while ((m = regex.exec(html)) !== null) {
  matches.push(m[1]);
}

console.log('Found', matches.length, 'base64 PNG images');

// Map by position in the HTML
const mapping = [
  { idx: 0, name: 'cap-adaptive.png', desc: 'Adaptive Tutoring icon' },
  { idx: 1, name: 'cap-evolutionary.png', desc: 'Evolutionary Feedback icon' },
  { idx: 2, name: 'cap-agent.png', desc: 'Agent Harness icon' },
  { idx: 3, name: 'cap-teaching.png', desc: 'Learn by Teaching icon' },
  { idx: 4, name: 'crt-monitor.png', desc: 'CRT monitor frame' },
  { idx: 5, name: 'mascot-lotus.png', desc: 'Lotus pose mascot' },
  { idx: 6, name: 'wordmark-footer.png', desc: 'Footer wordmark' },
];

for (const { idx, name, desc } of mapping) {
  if (idx >= matches.length) {
    console.error(`Missing image ${idx}: ${name}`);
    continue;
  }
  const data = Buffer.from(matches[idx], 'base64');
  const outPath = path.join(outDir, name);
  fs.writeFileSync(outPath, data);
  console.log(`✓ ${name} (${desc}) — ${data.length} bytes`);
}

console.log('Done! All images extracted to', outDir);

