input.oldString:
/* ---------- loop / harness ---------- */
.retro-layout .loop {
  background: var(--terminal);
  border-top: 1.5px solid var(--ink);
  border-bottom: 1.5px solid var(--ink);
  padding: 74px 0 0;
  position: relative;
}

.retro-layout .loop::before {
  content: '';
  position: absolute;
  inset: 0;
  pointer-events: none;
  background: repeating-linear-gradient(0deg, rgba(0, 0, 0, 0.15) 0 1px, transparent 1px 3px);
}

.retro-layout .loop .wrap {
  position: relative;
}

.retro-layout .loop-head {
  display: grid;
  grid-template-columns: 280px 1fr;
  gap: 40px;
  align-items: start;
  padding-bottom: 56px;
}

.retro-layout .loop-head h2 {
  font-family: var(--mono-display);
  font-weight: 700;
  color: var(--phosphor);
  font-size: 22px;
  letter-spacing: 0.04em;
  margin-bottom: 14px;
}

.retro-layout .loop-head p {
  color: var(--phosphor-dim);
  font-size: 13.5px;
  max-width: 34ch;
}

.retro-layout .loop-steps {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 14px;
}

.retro-layout .loop-step {
  border: 1px solid rgba(75, 227, 136, 0.35);
  padding: 18px 16px 20px;
  position: relative;
  background: rgba(75, 227, 136, 0.04);
}

.retro-layout .loop-step:not(:last-child)::after {
  content: '»';
  position: absolute;
  right: -13px;
  top: 50%;
  transform: translateY(-50%);
  color: var(--phosphor-dim);
  font-size: 16px;
  z-index: 2;
}

.retro-layout .loop-step h4 {
  font-family: var(--mono-display);
  color: var(--phosphor);
  font-size: 14px;
  letter-spacing: 0.08em;
  margin-bottom: 8px;
}

.retro-layout .loop-step h4 span {
  color: var(--phosphor-dim);
  margin-right: 8px;
}

.retro-layout .loop-step p {
  color: var(--phosphor-dim);
  font-size: 12.5px;
  line-height: 1.7;
}

.retro-layout .loop-bar {
  margin-top: 58px;
  border-top: 1px solid rgba(75, 227, 136, 0.25);
  padding: 13px 0;
  font-size: 12px;
  color: var(--phosphor-dim);
  letter-spacing: 0.06em;
}

.retro-layout .loop-bar b {
  color: var(--phosphor);
  font-weight: 600;
}

input.newString:
/* ---------- CLI use surface ---------- */
.retro-layout .use {
  padding: 90px 0;
  border-top: 1.5px dashed var(--line);
}

.retro-layout .use-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 18px;
  margin-bottom: 38px;
}

.retro-layout .use-card {
  background: var(--card);
  border: 1.5px solid var(--ink);
  padding: 24px 22px 26px;
  box-shadow: var(--shadow-card);
  transition: transform 0.16s ease, box-shadow 0.16s ease;
}

.retro-layout .use-card:hover {
  transform: translateY(-4px);
  box-shadow: 5px 5px 0 var(--ink);
}

.retro-layout .use-card-title {
  font-family: var(--mono-display);
  font-weight: 700;
  font-size: 15.5px;
  letter-spacing: 0.06em;
  color: var(--accent-dim);
  margin-bottom: 6px;
}

.dark .retro-layout .use-card-title {
  color: var(--phosphor);
}

.retro-layout .use-card-blurb {
  color: var(--ink-soft);
  font-size: 12.5px;
  line-height: 1.6;
  margin-bottom: 14px;
}

.retro-layout .use-cmds {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.retro-layout .use-cmd {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.retro-layout .use-cmd code {
  font-family: var(--mono-body);
  font-size: 12.5px;
  color: var(--ink);
}

.retro-layout .use-cmd code span {
  color: var(--accent-dim);
}

.dark .retro-layout .use-cmd code span {
  color: var(--phosphor);
}

.retro-layout .use-cmd small {
  font-size: 11.5px;
  color: var(--ink-soft);
}

.retro-layout .use-links {
  display: flex;
  gap: 16px;
  flex-wrap: wrap;
}

/* ---------- install — CRT terminal ---------- */
.retro-layout .install {
  padding: 90px 0;
  border-top: 1.5px dashed var(--line);
}

.retro-layout .install-term {
  position: relative;
  background: var(--terminal);
  border: 1.5px solid var(--ink);
  box-shadow: 6px 6px 0 var(--ink);
  max-width: 720px;
}

.retro-layout .install-term-bar {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 11px 14px;
  background: var(--terminal-edge);
  border-bottom: 1px solid rgba(75, 227, 136, 0.18);
}

.retro-layout .install-term-bar .d {
  width: 11px;
  height: 11px;
  border-radius: 50%;
}

.retro-layout .install-term-bar .d.r { background: var(--red); }
.retro-layout .install-term-bar .d.y { background: var(--amber); }
.retro-layout .install-term-bar .d.g { background: var(--accent); }

.retro-layout .install-term-title {
  margin-left: 8px;
  font-size: 11px;
  letter-spacing: 0.14em;
  color: var(--phosphor-dim);
  flex: 1;
}

.retro-layout .install-copy {
  font-family: var(--mono-body);
  font-size: 11px;
  letter-spacing: 0.1em;
  padding: 5px 10px;
  border: 1px solid rgba(75, 227, 136, 0.45);
  color: var(--phosphor);
  background: transparent;
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
}

.retro-layout .install-copy:hover {
  background: rgba(75, 227, 136, 0.12);
}

.retro-layout .install-copy.copied {
  background: rgba(75, 227, 136, 0.25);
  color: var(--phosphor);
}

.retro-layout .install-term-tabs {
  display: flex;
  gap: 0;
  border-bottom: 1px solid rgba(75, 227, 136, 0.18);
  background: rgba(0, 0, 0, 0.25);
  overflow-x: auto;
}

.retro-layout .install-term-tabs button {
  font-family: var(--mono-body);
  font-size: 12px;
  letter-spacing: 0.06em;
  padding: 10px 16px;
  background: transparent;
  border: none;
  border-right: 1px solid rgba(75, 227, 136, 0.12);
  color: var(--phosphor-dim);
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
  white-space: nowrap;
}

.retro-layout .install-term-tabs button:hover {
  background: rgba(75, 227, 136, 0.08);
  color: var(--phosphor);
}

.retro-layout .install-term-tabs button.active {
  background: rgba(75, 227, 136, 0.14);
  color: var(--phosphor);
}

.retro-layout .install-term-body {
  position: relative;
  padding: 22px 24px 26px;
  font-size: 13.5px;
  line-height: 1.85;
  color: var(--phosphor);
  min-height: 120px;
}

.retro-layout .install-term-body::after {
  content: '';
  position: absolute;
  inset: 0;
  pointer-events: none;
  background: repeating-linear-gradient(0deg, rgba(0, 0, 0, 0.16) 0 1px, transparent 1px 3px);
  mix-blend-mode: multiply;
}

.retro-layout .install-term-body .t-line {
  white-space: pre-wrap;
  word-break: break-word;
  min-height: 1.85em;
  position: relative;
  z-index: 1;
}

.retro-layout .install-term-body .t-cmd::before {
  content: '$ ';
  color: var(--phosphor-dim);
}

.retro-layout .install-term-body .t-sys {
  color: var(--phosphor-dim);
  font-style: italic;
}

.retro-layout .install-term-body .t-ok {
  color: var(--phosphor);
  font-weight: 600;
}

.retro-layout .install-term-body .t-indent {
  padding-left: 18px;
  color: rgba(220, 239, 224, 0.8);
}

